def gen(rng, size):
    n = max(2, size)
    nums = []
    while len(nums) < n:
        if rng.random() < 0.05:
            base = rng.randint(2, 300)
            v = base
            while v <= 100000 and len(nums) < n:
                nums.append(v)
                v = v * v
        else:
            nums.append(rng.randint(2, 100000))
    rng.shuffle(nums)
    return [nums[:n]]

