class Solution:
    def longestSquareStreak(self, nums):
        vals = set(nums)
        best = -1
        for v in vals:
            root = int(v ** 0.5)
            is_root_present = False
            for r in (root - 1, root, root + 1):
                if r * r == v and r in vals:
                    is_root_present = True
                    break
            if is_root_present:
                continue
            length = 1
            cur = v
            while cur * cur in vals:
                cur = cur * cur
                length += 1
            if length >= 2:
                best = max(best, length)
        return best

