var longestSquareStreak = function(nums) {
    const vals = new Set(nums);
    let best = -1;
    for (const v of vals) {
        const root = Math.round(Math.sqrt(v));
        let rootPresent = false;
        for (const r of [root - 1, root, root + 1]) {
            if (r * r === v && vals.has(r)) { rootPresent = true; break; }
        }
        if (rootPresent) continue;
        let length = 1;
        let cur = v;
        while (vals.has(cur * cur)) {
            cur = cur * cur;
            length++;
        }
        if (length >= 2 && length > best) best = length;
    }
    return best;
};
